class ExpirationModalHandler{constructor(){this.userId=expirationModalData.userId,this.nonce=expirationModalData.nonce,this.ajaxurl=expirationModalData.ajaxurl,this.init()}init(){this.setupEventListeners()}setupEventListeners(){this.waitForModal().then(e=>{this.setupModalCloseHandler(e)})}waitForModal(){return new Promise(e=>{const o=()=>{const t=document.getElementById("expiration-modal");t?e(t):setTimeout(o,100)};o()})}setupModalCloseHandler(e){e.addEventListener("close",()=>{this.handleExpirationModalClose(e)})}handleExpirationModalClose(e){this.userId&&this.nonce&&this.disableExpirationModal(this.userId,this.nonce)}disableExpirationModal(e,o){fetch(this.ajaxurl,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams({action:"disable_expiration_modal",user_id:e,nonce:o})}).then(e=>e.json()).then(e=>{e.success?console.log("Expiration modal successfully disabled."):console.error("Error disabling the modal:",e.data)}).catch(e=>{console.error("Request error:",e)})}}document.addEventListener("DOMContentLoaded",()=>{document.getElementById("expiration-modal")&&(window.expirationModalHandler=new ExpirationModalHandler)});